starterCode.javascript:
const express = require('express');
const app = express();
app.use((req, res, next) => {
    console.log("Middleware 1");
    next();
});
app.use((req, res, next) => {
    console.log("Middleware 2");
    next();
});
app.get('/', (req, res) => {
    res.json({
        statusCode: 200,
        message: "Hello, World!"
    });
});
app.listen(3000, () => {
    console.log("Server listening on port 3000");
});

starterCode.python:
from fastapi import FastAPI
app = FastAPI()
@app.middleware("http")
def middleware_1(request, call_next):
    print("Middleware 1")
    return call_next(request)
@app.middleware("http")
def middleware_2(request, call_next):
    print("Middleware 2")
    return call_next(request)
@app.get("/")
def read_root():
    return {
        "statusCode": 200,
        "message": "Hello, World!"
    }

